DROP TABLE IF EXISTS `monitor_behavior_data`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `monitor_behavior_data` (
  `id` int NOT NULL AUTO_INCREMENT,
  `cattleId` int NOT NULL,
  `penId` int DEFAULT NULL,
  `behaviorType` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `startTime` datetime(3) NOT NULL,
  `endTime` datetime(3) DEFAULT NULL,
  `duration` int DEFAULT NULL,
  `cameraId` int DEFAULT NULL,
  `confidence` double DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  PRIMARY KEY (`id`),
  KEY `monitor_behavior_data_cattleId_fkey` (`cattleId`),
  KEY `monitor_behavior_data_cameraId_fkey` (`cameraId`),
  CONSTRAINT `monitor_behavior_data_cameraId_fkey` FOREIGN KEY (`cameraId`) REFERENCES `shared_cameras` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `monitor_behavior_data_cattleId_fkey` FOREIGN KEY (`cattleId`) REFERENCES `shared_cattle` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3746 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

