--
-- Table structure for table `monitor_daily_statistics`
--

DROP TABLE IF EXISTS `monitor_daily_statistics`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `monitor_daily_statistics` (
  `id` int NOT NULL AUTO_INCREMENT,
  `cattleId` int NOT NULL,
  `statDate` date NOT NULL,
  `eatingTime` int NOT NULL DEFAULT '0',
  `standingTime` int NOT NULL DEFAULT '0',
  `lyingTime` int NOT NULL DEFAULT '0',
  `walkingTime` int NOT NULL DEFAULT '0',
  `drinkingTime` int NOT NULL DEFAULT '0',
  `totalActiveTime` int NOT NULL DEFAULT '0',
  `isEstrus` tinyint(1) NOT NULL DEFAULT '0',
  `estrusIntensity` float DEFAULT NULL COMMENT '氓聫鈥樏ζ掆€γヂ悸好ヂ郝?0-1',
  `lastBreedingDate` date DEFAULT NULL COMMENT '盲赂艩忙卢隆茅鈥β嵜嵜︹€斅ッε撆?,
  `pregnancyStatus` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '氓娄艩氓篓聽莽艩露忙鈧? open/bred/pregnant/calving',
  PRIMARY KEY (`id`),
  UNIQUE KEY `monitor_daily_statistics_cattleId_statDate_key` (`cattleId`,`statDate`),
  CONSTRAINT `monitor_daily_statistics_cattleId_fkey` FOREIGN KEY (`cattleId`) REFERENCES `shared_cattle` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2864 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

